order by id desc;

select

from cer_vector_task_tb
where vector_task_type !='2' and vector_task_code not
in('TM01201-OH01','TM01201-OH02','TS00101-AB01','TS00101-AB02','CM00301-GN01','CM00301-GN02','TM01201-OH03','TS00101-BZ03','TS00101-SQ04','TM01201-OH04')
and project_id = #{projectId,jdbcType=INTEGER}
and task_status =#{taskStatus,jdbcType=VARCHAR}
and species_code = #{speciesCode,jdbcType=VARCHAR}
and project_id in (select id from cer_project_tb where
    owner_user_id=#{userId,jdbcType=INTEGER})

order by sub_project_code asc ,id asc

