order by id desc;

select

from cer_vector_task_tb

    and
        vector_task_code=#{vectorTaskCode,jdbcType=VARCHAR}

    and delivery_method=#{deliveryMethod,jdbcType=VARCHAR}
    and acceptor_material=#{acceptorMaterial,jdbcType=VARCHAR}
    and project_id=#{projectId,jdbcType=NUMERIC}
    and sub_project_id=#{subProjectId,jdbcType=NUMERIC}
    and project_code=#{projectCode,jdbcType=VARCHAR}
    and
        sub_project_code=#{subProjectCode,jdbcType=VARCHAR}

    and edit_type=#{editType,jdbcType=VARCHAR}
    and task_num=#{taskNum,jdbcType=VARCHAR}
    and task_status=#{taskStatus,jdbcType=VARCHAR}
    and species_code=#{speciesCode,jdbcType=VARCHAR}
    and breed_code=#{breedCode,jdbcType=VARCHAR}
    and current_step_code=#{currentStepCode,jdbcType=VARCHAR}
    and expected_positive_seed=#{expectedPositiveSeed,jdbcType=VARCHAR}

    and supervision_level_code=#{supervisionLevelCode,jdbcType=VARCHAR}

    and expect_start_date=#{expectStartDate,jdbcType=VARCHAR}
    and expect_period=#{expectPeriod,jdbcType=VARCHAR}
    and create_time=#{createTime,jdbcType=TIMESTAMP}
    and update_time=#{updateTime,jdbcType=TIMESTAMP}
    and create_user_id=#{createUserId,jdbcType=NUMERIC}
    and create_user_name=#{createUserName,jdbcType=VARCHAR}

order by id desc
